// Enumerate ALL nested enums + flags on Operation type so we can patch them in one pass.
var asm = System.Reflection.Assembly.Load("Tekla.Structures.Model");
var opType = asm.GetType("Tekla.Structures.Model.Operations.Operation");
var result = new System.Collections.Generic.Dictionary<string, object>();
foreach (var nested in opType.GetNestedTypes()) {
    if (!nested.IsEnum) continue;
    var values = new System.Collections.Generic.List<object>();
    foreach (var name in System.Enum.GetNames(nested)) {
        var val = System.Convert.ToInt64(System.Enum.Parse(nested, name));
        values.Add(new { name = name, value = val });
    }
    string fqn = "Tekla.Structures.Model.Operations.Operation." + nested.Name;
    result[fqn] = new {
        is_flags = nested.IsDefined(typeof(System.FlagsAttribute), false),
        underlying_type = System.Enum.GetUnderlyingType(nested).Name,
        values = values
    };
}
return result;
